"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[9849],{3371:(D,B,e)=>{e.r(B),e.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-0848a2f0","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%BE%D0%B4%D0%B0%D1%80%D0%B8%D1%87-%D0%BF%D1%80%D0%BE%D0%B1%D0%BB%D0%B5%D0%BC%D0%B0-%D0%BE%D1%82%D1%87%D1%83%D0%B6%D0%B4%D0%B5%D0%BD%D0%B8%D1%8F-%D0%B2-%D0%BA%D0%BE%D0%BD%D1%82%D0%B5%D0%BA%D1%81%D1%82%D0%B5-%D1%82%D0%B5%D0%BE%D1%80%D0%B8%D0%B8-%D0%B8%D0%BD%D1%84%D0%BE%D1%80%D0%BC%D0%B0%D1%86%D0%B8%D0%BE%D0%BD%D0%BD%D1%8B%D1%85.html","title":"Проблема отчуждения в контексте теории информационных барьеров В. М. Глушкова","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1730914103000},"filePathRelative":"глушковские-чтения/одарич-проблема-отчуждения-в-контексте-теории-информационных.md"}')},3785:(D,B,e)=>{e.r(B),e.d(B,{default:()=>p});var l=e(6252);const t=(0,l._)("h1",{id:"проблема-отчуждения-в-контексте-теории-информационных-барьеров-в-м-глушкова",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#проблема-отчуждения-в-контексте-теории-информационных-барьеров-в-м-глушкова","aria-hidden":"true"},"#"),(0,l.Uk)(" Проблема отчуждения в контексте теории информационных барьеров В. М. Глушкова")],-1),a=(0,l._)("p",null,"Одарич C. В. г. Киев. Перевод с украинского.",-1),r=(0,l._)("p",null,"Важность понятия отчуждения несомненна для европейской интеллектуальной традиции. Разработка его начинается в социальной философии Нового времени в трудах Т. Гоббса, Ж.-Ж. Руссо, Дж. Локка, где оно понимается как важная характеристика общества, все без исключения функции которого становятся предметом частной практики отдельных институтов и социальных агентов, их профессиональным занятием, что приводит к приватизации этих функции ими, а каждого человека ставит в позицию зависимости и подчинённости, опосредованную логикой закона и бюрократической процессуальностью. Необходимость возникновения отчуждения диктуется усложнением социального устройства. От человека требуется повиноваться власти, принимать такое чужое положение вещей как данность, а собственную волю корректировать в соответствии с действующим нормативным порядком. Философско-идеалистическое оформление категория отчуждения приобретает в трудах Г. В. Ф. Гегеля, который видит в отчуждении историческую необходимость, основополагающее условие для становления сознания индивида, а само отчуждение трактует как внешнюю реализацию Абсолютного Духа.",-1),n=(0,l._)("p",null,"Материалистическую критику проблема отчуждения получает в теоретизировании К. Маркса, для творчества которого она становится одной из центральных. Простыми словами, отчуждение — это история об утрате человеком смысла бытия в ходе труда, что прямо зависит от углубления его общественного разделения. Отчуждение прямо зависит от роста дифференциации социальных практик, от углубления материального неравенства и доступа к благам, от расщепления и ветвления социального сознания, его индивидуализации, вызванной ростом профессионализации и вызванных ею деформаций. К. Маркс выделял четыре вида отчуждения: от процесса труда, от продукта труда, от человеческой сущности и отчуждение людей друг от друга. Виды отчуждения являются одновременно и сущностными, и историческими, то есть, одновременно и видами, и этапами, а потому их сущностное преодоление возможно в последовательно обратном к историческому возникновению направлении. Согласно марксистской идеологии, преодолеть отчуждение и вернуть человеку его человеческую сущность возможно в результате социальной революции, уничтожив антагонистический социально-классовый порядок и реализовав радикальную демократию.",-1),u=(0,l._)("p",null,"Итак, получив рождение в философии, со временем концепт отчуждения прочно вошел в понятийные аппараты многих наук, а особенно — социогуманитарного цикла. Попробуем рассмотреть проблему отчуждения сквозь оптику теории информационных барьеров В. М. Глушкова. Согласно этой теории, историческое развитие человечества проходит через два важных этапа. На первом этапе возникает письменность, что делает возможным создание иерархических систем социального управления, что в свою очередь позволяет перейти от доисторического примитивного родоплеменного (неантагонистического) социального устройства к цивилизации (в различных вариациях антагонистических обществ), преодолеть первый информационный барьер. Второй информационный барьер — это невозможность дальнейшего управления высокотехнологичной цивилизацией и глобальным обществом без автоматизации информационной работы. Преодолеть его можно благодаря принципиально иной информатике — цифровой, «небумажной», пользуясь термином В. М. Глушкова. Теория информационных барьеров позволяет взглянуть на историческое развитие человечества под принципиально иным углом, чем это было до ее возникновения. Так, появляется возможность для радикальной ревизии исторической науки. Например, историческая формация перестает в таком случае быть детерминированной способом производства, который из детерминанты превращается в переменную, зависящую от материальных условий осуществления коммуникации, системного управления в социальной системе общества. А значит и все развитие человечества от примитивных неантагонистических укладов через сложные антагонистические к непримитивным неантагонистическим становится возможным благодаря не смене формации, но через изменение материальной базы информатики, поскольку сами формации и являются результатом функционирования информатики, результатом материальных условий осуществления коммуникации.",-1),d=(0,l._)("p",null,"Так же и с отчуждением: развитие средств коммуникации уже сегодня позволяет говорить о размывании границ отчуждения людей друг от друга в масштабах и способах, которые были невозможны в условиях исключительно «бумажной информатики». Новые коммуникации второго цифрового барьера позволяют радикализировать проблему прямой демократии, дебюрократизации (деиерархизации в старом понимании) всех сфер общественного производства, всех без исключения материальных и нематериальных практик, проблему соотношения индивидуальных и коллективных интересов, что приведет к преодолению всех без исключения видов отчуждения, вплоть до отчуждения от процесса труда. Наконец, речь идет даже о преодолении труда как социального отношения путем снятия товарного производства именно благодаря возможному уже сегодня (благодаря цифровым коммуникациям, «небумажной информатике» после второго информационного барьера) формированию консолидированного спроса в произвольном масштабировании и его удовлетворению, а не идеологическому выруливанию между свободным рынком и планомерным регулированием в традиционном политическом и экономическом понимании.",-1),i=(0,l._)("p",null,"Теория информационных барьеров В. М. Глушкова как пример кибернетического подхода к историческому анализу эволюции и развития социальных систем требует самого пристального исследования учеными для выработки позитивной повестки дня. Однако, по словам Н.Лумана, «староевропейская семантика», в которую в том числе входит и марксизм (по крайней мере, как идеология, программа и платформа), здесь бессильна, а значит — нужен новый, соответствующий времени и уровню развития теоретический инструментарий для программы социальных изменений, который бы основывался на методологических основах кибернетики и смежных дисциплин. Убежден, что именно и только тогда удастся достичь недостижимой пока цели гуманистического нерепрессивного управления обществом, опирающегося на науки об обществе.",-1),h={},p=(0,e(3744).Z)(h,[["render",function(D,B){const e=(0,l.up)("RouterLink");return(0,l.wg)(),(0,l.iD)("div",null,[t,a,(0,l._)("p",null,[(0,l.Uk)("Из материалов конференции "),(0,l.Wm)(e,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,l.w5)((()=>[(0,l.Uk)("«Глушковские чтения»")])),_:1}),(0,l.Uk)(" 2016 года.")]),r,n,u,d,i])}]])}}]);